import {
  DownloadIcon,
  EyeIcon,
  ArrowLeftIcon,
  InformationCircleIcon,
} from '@heroicons/react/outline'
import React, { useCallback, useEffect, useRef, useState } from 'react'
import { useWindowSize } from 'react-use'
import inpaint, { onModelProgress } from './adapters/inpainting'
import Button from './components/Button'
import Slider from './components/Slider'
import { downloadImage, loadImage, useImage } from './utils'

interface EditorProps {
  file: File
  onNewImage: () => void
  onAbout: () => void
}

interface Line {
  size?: number
  pts: { x: number; y: number }[]
}

function drawLines(
  ctx: CanvasRenderingContext2D,
  lines: Line[],
  color = 'rgba(255, 0, 0, 0.5)'
) {
  ctx.strokeStyle = color
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  lines.forEach(line => {
    if (!line?.pts.length || !line.size) {
      return
    }
    ctx.lineWidth = line.size
    ctx.beginPath()
    ctx.moveTo(line.pts[0].x, line.pts[0].y)
    line.pts.forEach(pt => ctx.lineTo(pt.x, pt.y))
    ctx.stroke()
  })
}

function getCanvasStyle(
  w: number,
  h: number,
  scale: number,
  showBrush: boolean
): React.CSSProperties {
  if (!w) return {}
  const base: React.CSSProperties = {
    width: `${w * scale}px`,
    height: `${h * scale}px`,
  }
  if (showBrush) base.cursor = 'none'
  return base
}

export default function Editor(props: EditorProps) {
  const { file, onNewImage, onAbout } = props
  const [brushSize, setBrushSize] = useState(40)
  const [original, isOriginalLoaded] = useImage(file)
  const [render] = useState(new Image())
  const [context, setContext] = useState<CanvasRenderingContext2D>()
  const [maskCanvas] = useState<HTMLCanvasElement>(() => {
    return document.createElement('canvas')
  })
  const [lines] = useState<Line[]>([{ pts: [] }])
  const [{ x, y }, setCoords] = useState({ x: -1, y: -1 })
  const [showBrush, setShowBrush] = useState(false)
  const [showOriginal, setShowOriginal] = useState(false)
  const [isInpaintingLoading, setIsInpaintingLoading] = useState(false)
  const [showSeparator, setShowSeparator] = useState(false)
  const [modelStatus, setModelStatus] = useState<string>('')
  const [scale, setScale] = useState(1)
  const windowSize = useWindowSize()
  // Store the raw model output for download (bypasses canvas export)
  const latestResultRef = useRef<string | null>(null)

  // Register model progress callback
  useEffect(() => {
    onModelProgress((progress: number) => {
      setModelStatus(`AI 模型下载中... ${progress}%`)
    })
  }, [])

  const draw = useCallback(() => {
    if (!context) {
      return
    }
    context.clearRect(0, 0, context.canvas.width, context.canvas.height)
    if (render.src) {
      context.drawImage(render, 0, 0)
    } else {
      context.drawImage(original, 0, 0)
    }
    const currentLine = lines[lines.length - 1]
    drawLines(context, [currentLine])
  }, [context, lines, original, render])

  const refreshCanvasMask = useCallback(() => {
    if (!context?.canvas.width || !context?.canvas.height) {
      throw new Error('canvas has invalid size')
    }
    maskCanvas.width = context?.canvas.width
    maskCanvas.height = context?.canvas.height
    const ctx = maskCanvas.getContext('2d')
    if (!ctx) {
      throw new Error('could not retrieve mask canvas')
    }
    drawLines(ctx, lines, 'white')
  }, [context?.canvas.height, context?.canvas.width, lines, maskCanvas])

  // Draw once the original image is loaded
  useEffect(() => {
    if (!context?.canvas) {
      return
    }
    if (isOriginalLoaded) {
      context.canvas.width = original.naturalWidth
      context.canvas.height = original.naturalHeight
      const rW = windowSize.width / original.naturalWidth
      const rH = (windowSize.height - 200) / original.naturalHeight
      if (rW < 1 || rH < 1) {
        setScale(Math.min(rW, rH))
      } else {
        setScale(1)
      }
      draw()
    }
  }, [context?.canvas, draw, original, isOriginalLoaded, windowSize])

  // Handle mouse interactions
  useEffect(() => {
    const canvas = context?.canvas
    if (!canvas) {
      return
    }
    const onMouseMove = (ev: MouseEvent) => {
      setCoords({ x: ev.pageX, y: ev.pageY })
    }
    const onPaint = (px: number, py: number) => {
      const currLine = lines[lines.length - 1]
      currLine.pts.push({ x: px, y: py })
      draw()
    }
    const onMouseDrag = (ev: MouseEvent) => {
      const rect = canvas.getBoundingClientRect()
      const px = (ev.clientX - rect.left) / scale
      const py = (ev.clientY - rect.top) / scale
      onPaint(px, py)
    }

    const onPointerUp = async () => {
      if (!original.src) {
        return
      }
      setIsInpaintingLoading(true)
      canvas.removeEventListener('mousemove', onMouseDrag)
      window.removeEventListener('mouseup', onPointerUp)
      refreshCanvasMask()
      try {
        const res = await inpaint(file, maskCanvas.toDataURL())
        if (!res) {
          throw new Error('empty response')
        }
        const canvasW = context.canvas.width
        const canvasH = context.canvas.height
        // Verify result dimensions match canvas
        const resultImg = new Image()
        await new Promise<void>((resolve, reject) => {
          resultImg.onload = () => resolve()
          resultImg.onerror = reject
          resultImg.src = res
        })
        setModelStatus(
          `原图: ${canvasW}x${canvasH} | 模型输出: ${resultImg.naturalWidth}x${resultImg.naturalHeight}`
        )
        if (
          resultImg.naturalWidth !== canvasW ||
          resultImg.naturalHeight !== canvasH
        ) {
          // Resize model output to match original dimensions
          const fixCanvas = document.createElement('canvas')
          fixCanvas.width = canvasW
          fixCanvas.height = canvasH
          const fixCtx = fixCanvas.getContext('2d') as CanvasRenderingContext2D
          fixCtx.imageSmoothingEnabled = false
          fixCtx.drawImage(resultImg, 0, 0, canvasW, canvasH)
          const fixedDataUrl = fixCanvas.toDataURL('image/png')
          // Update both display and download reference
          latestResultRef.current = fixedDataUrl
          await loadImage(render, fixedDataUrl)
        } else {
          // Dimensions match — store for download
          latestResultRef.current = res
          await loadImage(render, res)
        }
        setModelStatus('AI 处理完成，点击 Download 下载')
      } catch (e: any) {
        setModelStatus('')
        // eslint-disable-next-line
        alert(e.message ? e.message : e.toString())
      }

      lines.push({ pts: [] } as Line)
      setIsInpaintingLoading(false)
      draw()
    }
    window.addEventListener('mousemove', onMouseMove)

    const onTouchMove = (ev: TouchEvent) => {
      ev.preventDefault()
      ev.stopPropagation()
      const currLine = lines[lines.length - 1]
      const coords = canvas.getBoundingClientRect()
      currLine.pts.push({
        x: (ev.touches[0].clientX - coords.x) / scale,
        y: (ev.touches[0].clientY - coords.y) / scale,
      })
      draw()
    }
    const onPointerStart = () => {
      if (!original.src) {
        return
      }
      const currLine = lines[lines.length - 1]
      currLine.size = brushSize
      canvas.addEventListener('mousemove', onMouseDrag)
      window.addEventListener('mouseup', onPointerUp)
      // onPaint(e)
    }

    canvas.addEventListener('touchstart', onPointerStart)
    canvas.addEventListener('touchmove', onTouchMove)
    canvas.addEventListener('touchend', onPointerUp)
    canvas.onmouseenter = () => setShowBrush(true)
    canvas.onmouseleave = () => setShowBrush(false)
    canvas.onmousedown = onPointerStart

    return () => {
      canvas.removeEventListener('mousemove', onMouseDrag)
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('mouseup', onPointerUp)
      canvas.removeEventListener('touchstart', onPointerStart)
      canvas.removeEventListener('touchmove', onTouchMove)
      canvas.removeEventListener('touchend', onPointerUp)
      canvas.onmouseenter = null
      canvas.onmouseleave = null
      canvas.onmousedown = null
    }
  }, [
    brushSize,
    context,
    file,
    draw,
    lines,
    refreshCanvasMask,
    maskCanvas,
    original.src,
    render,
    original.naturalHeight,
    original.naturalWidth,
    scale,
  ])

  function download() {
    // Use raw model output if available (bypasses canvas CSS scaling issues)
    if (latestResultRef.current) {
      const name = file.name.replace(/(\.[\w\d_-]+)$/i, '_cleanup.png')
      downloadImage(latestResultRef.current, name)
      return
    }
    // Fallback: export from canvas
    const base64 = context?.canvas.toDataURL('image/png')
    if (!base64) {
      throw new Error('could not get canvas data')
    }
    const name = file.name.replace(/(\.[\w\d_-]+)$/i, '_cleanup.png')
    downloadImage(base64, name)
  }

  return (
    <div
      className={[
        'flex flex-col items-center',
        isInpaintingLoading ? 'animate-pulse-fast pointer-events-none' : '',
      ].join(' ')}
    >
      {(isInpaintingLoading || modelStatus) && (
        <div className="sticky top-0 z-0 bg-gray-800 bg-opacity-90 text-white text-center py-2 px-4">
          {isInpaintingLoading && !modelStatus && 'AI 处理中...'}
          {modelStatus && modelStatus}
        </div>
      )}

      {/* Toolbar between status bar and image */}
      <div className="flex items-center justify-center flex-wrap gap-3 w-full max-w-4xl px-4 py-2">
        <Button
          icon={<ArrowLeftIcon className="w-5 h-5" />}
          onClick={onNewImage}
        >
          Start new
        </Button>
        <Button icon={<DownloadIcon className="w-5 h-5" />} onClick={download}>
          Download
        </Button>
        <Slider
          label="Brush Size"
          min={10}
          max={150}
          value={brushSize}
          onChange={setBrushSize}
        />
        <Button
          icon={<EyeIcon className="w-6 h-6" />}
          onDown={() => {
            setShowSeparator(true)
            setShowOriginal(true)
          }}
          onUp={() => {
            setShowOriginal(false)
            setTimeout(() => setShowSeparator(false), 300)
          }}
        >
          Original
        </Button>
        <Button
          icon={<InformationCircleIcon className="w-5 h-5" />}
          onClick={onAbout}
        >
          About
        </Button>
      </div>

      <div className="relative inline-flex flex-col items-center">
        <canvas
          className="rounded-sm"
          style={getCanvasStyle(
            original.naturalWidth,
            original.naturalHeight,
            scale,
            showBrush
          )}
          width={original.naturalWidth}
          height={original.naturalHeight}
          ref={r => {
            if (r && !context) {
              const ctx = r.getContext('2d')
              if (ctx) {
                setContext(ctx)
              }
            }
          }}
        />
        <div
          className={[
            'absolute top-0 right-0 pointer-events-none',
            'overflow-hidden',
            'border-primary',
            showSeparator ? 'border-l-4' : '',
          ].join(' ')}
          style={{
            width: showOriginal
              ? `${Math.round(original.naturalWidth * scale)}px`
              : '0px',
            height: original.naturalHeight * scale,
            transitionProperty: 'width, height',
            transitionTimingFunction: 'cubic-bezier(0.4, 0, 0.2, 1)',
            transitionDuration: '300ms',
          }}
        >
          <img
            className="absolute right-0"
            src={original.src}
            alt="original"
            width={`${original.naturalWidth * scale}px`}
            height={`${original.naturalHeight * scale}px`}
            style={{
              width: `${original.naturalWidth * scale}px`,
              height: `${original.naturalHeight * scale}px`,
              maxWidth: 'none',
            }}
          />
        </div>
      </div>

      {showBrush && (
        <div
          className="hidden sm:block absolute rounded-full bg-red-500 bg-opacity-50 pointer-events-none"
          style={{
            width: `${brushSize}px`,
            height: `${brushSize}px`,
            left: `${x}px`,
            top: `${y}px`,
            transform: 'translate(-50%, -50%)',
          }}
        />
      )}

    </div>
  )
}
