import localforage from 'localforage'

// Use global ort from CDN (loaded via index.html script tag)
// eslint-disable-next-line @typescript-eslint/no-explicit-any, prefer-destructuring
const ort = (window as any).ort

// Configure ONNX Runtime WASM path - use CDN base path
ort.env.wasm.wasmPaths =
  'https://cdn.jsdelivr.net/npm/onnxruntime-web@1.20.0/dist/'

// MI-GAN model (browser-compatible, standard ONNX ops only)
const MODEL_URL = '/models/model.onnx'
const MODEL_CACHE_KEY = 'migan_onnx_model_v2'

type ModelState = 'idle' | 'loading' | 'loaded' | 'error'
type ProgressCallback = (progress: number) => void

let modelState: ModelState = 'idle'
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let modelSession: any = null
let progressCallback: ProgressCallback | null = null

// Configure ONNX Runtime for browser
ort.env.wasm.numThreads = 1

/**
 * Get current model loading state
 */
export function getModelState(): ModelState {
  return modelState
}

/**
 * Register progress callback
 */
export function onModelProgress(callback: ProgressCallback) {
  progressCallback = callback
}

/**
 * Convert RGBA Uint8 array to CHW Uint8 array for model input (no resize)
 */
function rgbaToChw(
  rgba: Uint8ClampedArray,
  height: number,
  width: number
): Uint8Array {
  const totalPixels = height * width
  const chw = new Uint8Array(3 * totalPixels)
  for (let i = 0; i < totalPixels; i += 1) {
    chw[i] = rgba[i * 4] // R
    chw[totalPixels + i] = rgba[i * 4 + 1] // G
    chw[2 * totalPixels + i] = rgba[i * 4 + 2] // B
  }
  return chw
}

/**
 * Get Uint8Array pixel data from an image source at its natural resolution
 */
function getImagePixels(src: HTMLImageElement | HTMLCanvasElement): {
  data: Uint8ClampedArray
  width: number
  height: number
} {
  const canvas = document.createElement('canvas')
  const w = src instanceof HTMLImageElement ? src.naturalWidth : src.width
  const h = src instanceof HTMLImageElement ? src.naturalHeight : src.height
  canvas.width = w
  canvas.height = h
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D
  ctx.drawImage(src, 0, 0)
  const imageData = ctx.getImageData(0, 0, w, h)
  return { data: imageData.data, width: w, height: h }
}

/**
 * Convert CHW uint8 array to ImageData on a canvas (no resize)
 */
function chwToDataUrl(data: Uint8Array, height: number, width: number): string {
  const totalPixels = height * width
  const canvas = document.createElement('canvas')
  canvas.width = width
  canvas.height = height
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D
  const imageData = ctx.createImageData(width, height)

  for (let i = 0; i < totalPixels; i += 1) {
    imageData.data[i * 4] = data[i] // R
    imageData.data[i * 4 + 1] = data[totalPixels + i] // G
    imageData.data[i * 4 + 2] = data[2 * totalPixels + i] // B
    imageData.data[i * 4 + 3] = 255 // A
  }

  ctx.putImageData(imageData, 0, 0)
  return canvas.toDataURL('image/png')
}

/**
 * Load or retrieve cached model
 */
async function loadModel() {
  if (modelSession) {
    return modelSession
  }

  modelState = 'loading'

  try {
    // Try to load from IndexedDB cache first
    const cachedModel = await localforage.getItem<ArrayBuffer>(MODEL_CACHE_KEY)

    let modelBuffer: ArrayBuffer

    if (cachedModel) {
      modelBuffer = cachedModel
    } else {
      // Download model with progress tracking
      const response = await fetch(MODEL_URL)
      if (!response.ok) {
        throw new Error(`Failed to fetch model: ${response.status}`)
      }

      const total = Number(response.headers.get('content-length')) || 0
      const reader = response.body?.getReader()

      if (!reader) {
        throw new Error('No reader available')
      }

      const chunks: Uint8Array[] = []
      let loaded = 0

      // eslint-disable-next-line no-constant-condition
      while (true) {
        // eslint-disable-next-line no-await-in-loop
        const { done, value } = await reader.read()
        if (done) break
        if (value) {
          chunks.push(value)
          loaded += value.length
          if (total > 0 && progressCallback) {
            progressCallback(Math.round((loaded / total) * 100))
          }
        }
      }

      modelBuffer = new Uint8Array(loaded).buffer
      let position = 0
      chunks.forEach(chunk => {
        new Uint8Array(modelBuffer).set(chunk, position)
        position += chunk.length
      })

      // Cache the model
      await localforage.setItem(MODEL_CACHE_KEY, modelBuffer)
    }

    // Create ONNX session
    modelSession = await ort.InferenceSession.create(modelBuffer, {
      executionProviders: ['wasm'],
    })

    modelState = 'loaded'
    return modelSession
  } catch (error) {
    modelState = 'error'
    throw error
  }
}

/**
 * Main inpainting function using MI-GAN ONNX model
 * No resizing at any stage — preserves exact original pixel dimensions.
 */
export default async function inpaint(
  imageFile: File,
  maskBase64: string
): Promise<string> {
  // Load model if not already loaded
  const session = await loadModel()
  const { inputNames, outputNames } = session

  // Load original image pixels at full natural resolution
  const img = new Image()
  await new Promise<void>((resolve, reject) => {
    img.onload = () => resolve()
    img.onerror = reject
    img.src = URL.createObjectURL(imageFile)
  })

  const { data: imgPixels, width: imgW, height: imgH } = getImagePixels(img)

  // Load mask image pixels at matching resolution
  const maskImg = new Image()
  await new Promise<void>((resolve, reject) => {
    maskImg.onload = () => resolve()
    maskImg.onerror = reject
    maskImg.src = maskBase64
  })

  // Resize mask to match image dimensions (mask may be at display scale, not natural)
  const canvas = document.createElement('canvas')
  canvas.width = imgW
  canvas.height = imgH
  const ctx = canvas.getContext('2d') as CanvasRenderingContext2D
  ctx.imageSmoothingEnabled = false
  ctx.drawImage(maskImg, 0, 0, imgW, imgH)
  const maskPixels = ctx.getImageData(0, 0, imgW, imgH).data

  // Convert image RGBA -> CHW for model input
  const imageChw = rgbaToChw(imgPixels, imgH, imgW)

  // Convert mask: white brush (255) = inpaint area -> 0 for MI-GAN
  const maskChw = new Uint8Array(imgH * imgW)
  for (let i = 0; i < imgH * imgW; i += 1) {
    maskChw[i] = maskPixels[i * 4] > 127 ? 0 : 255
  }

  // Create tensors at original resolution
  const imageTensor = new ort.Tensor('uint8', imageChw, [1, 3, imgH, imgW])
  const maskTensor = new ort.Tensor('uint8', maskChw, [1, 1, imgH, imgW])

  // Run inference
  const feeds: Record<string, any> = {}
  feeds[inputNames[0]] = imageTensor
  feeds[inputNames[1]] = maskTensor

  const results = await session.run(feeds)
  const outputTensor = results[outputNames[0]]

  if (!outputTensor) {
    throw new Error('No output tensor from model')
  }

  // Convert output tensor to data URL at original dimensions
  return chwToDataUrl(outputTensor.data as Uint8Array, imgH, imgW)
}
